('Infographic', 'infographic', 'Visual layout with charts, icons, and modern design elements.', 'creative',
'<div class="cv-infographic"><div class="top-section"><div class="profile-area"><div class="avatar">{{photo}}</div><h1>{{first_name}} {{last_name}}</h1><p class="title">{{job_title}}</p></div><div class="contact-area">{{contact_entries}}</div></div><div class="body-section"><div class="col-main"><section class="summary"><h2>Profile</h2><p>{{summary}}</p></section><section class="experience"><h2>Experience</h2>{{experience_entries}}</section><section class="education"><h2>Education</h2>{{education_entries}}</section></div><div class="col-side"><section class="skills"><h2>Skills</h2>{{skills_entries}}</section><section class="languages"><h2>Languages</h2>{{language_entries}}</section><section class="interests"><h2>Interests</h2>{{interest_entries}}</section></div></div></div>',
'.cv-infographic{font-family:"Montserrat",sans-serif;max-width:850px;margin:0 auto;overflow:hidden}.cv-infographic .top-section{background:linear-gradient(135deg,#f093fb 0%,#f5576c 100%);color:#fff;padding:35px;display:flex;align-items:center;gap:25px}.cv-infographic .profile-area .avatar{width:100px;height:100px;border-radius:50%;background:rgba(255,255,255,0.2);display:flex;align-items:center;justify-content:center;font-size:36px;border:3px solid rgba(255,255,255,0.5)}.cv-infographic .profile-area h1{font-size:28px;font-weight:700;margin-bottom:3px}.cv-infographic .profile-area .title{font-size:14px;opacity:0.9}.cv-infographic .contact-area{margin-left:auto;font-size:12px;text-align:right;line-height:2}.cv-infographic .body-section{display:grid;grid-template-columns:65% 35%}.cv-infographic .col-main{padding:25px}.cv-infographic .col-side{background:#f8f9fa;padding:25px}.cv-infographic h2{font-size:13px;text-transform:uppercase;letter-spacing:2px;color:#f5576c;margin-bottom:12px}.cv-infographic .summary{font-size:14px;line-height:1.7;margin-bottom:20px}.cv-infographic .experience-entry{margin-bottom:15px}.cv-infographic .entry-title{font-weight:600;font-size:14px}.cv-infographic .entry-company{color:#f5576c;font-size:13px}.cv-infographic .entry-date{font-size:11px;color:#999}.cv-infographic .entry-description{font-size:13px;line-height:1.6}.cv-infographic .skill-bar{margin-bottom:10px}.cv-infographic .skill-name{font-size:12px;margin-bottom:3px}.cv-infographic .skill-track{background:#e9ecef;height:6px;border-radius:3px}.cv-infographic .skill-fill{background:linear-gradient(90deg,#f093fb,#f5576c);height:100%;border-radius:3px}',
8),

('Functional', 'functional', 'Skills-based layout organized by competency areas, great for career changers.', 'professional',
'<div class="cv-functional"><header><h1>{{first_name}} {{last_name}}</h1><p class="title">{{job_title}}</p><div class="contact">{{contact_entries}}</div></header><section class="summary"><h2>Career Summary</h2><p>{{summary}}</p></section><section class="skill-groups"><h2>Core Competencies</h2>{{skill_group_entries}}</section><section class="experience"><h2>Employment History</h2>{{experience_entries}}</section><section class="education"><h2>Education</h2>{{education_entries}}</section></div>',
'.cv-functional{font-family:"Open Sans",sans-serif;max-width:800px;margin:0 auto;padding:35px;color:#333}.cv-functional header{text-align:center;margin-bottom:25px}.cv-functional header h1{font-size:26px;color:#2c3e50;margin-bottom:5px}.cv-functional header .title{font-size:15px;color:#3498db;margin-bottom:8px}.cv-functional header .contact{font-size:13px;color:#666}.cv-functional h2{font-size:15px;color:#2c3e50;border-bottom:2px solid #3498db;padding-bottom:5px;margin:20px 0 12px}.cv-functional .summary{font-size:14px;line-height:1.7}.cv-functional .skill-group{margin-bottom:18px}.cv-functional .skill-group-title{font-weight:bold;font-size:14px;color:#3498db;margin-bottom:5px}.cv-functional .skill-group-items{font-size:13px;line-height:1.7;color:#444}.cv-functional .experience-entry{margin-bottom:12px;display:flex;justify-content:space-between}.cv-functional .entry-title{font-weight:600;font-size:13px}.cv-functional .entry-company{font-size:12px;color:#666}.cv-functional .entry-date{font-size:12px;color:#999}',
9),

('Combination', 'combination', 'Hybrid layout combining chronological experience with skills highlights.', 'professional',
'<div class="cv-combination"><header><h1>{{first_name}} {{last_name}}</h1><p class="title">{{job_title}}</p><div class="contact">{{contact_entries}}</div></header><section class="summary"><h2>Summary</h2><p>{{summary}}</p></section><section class="highlights"><h2>Key Qualifications</h2>{{highlight_entries}}</section><section class="experience"><h2>Professional Experience</h2>{{experience_entries}}</section><section class="education"><h2>Education</h2>{{education_entries}}</section><section class="skills"><h2>Skills</h2>{{skills_entries}}</section></div>',
'.cv-combination{font-family:"Roboto",sans-serif;max-width:800px;margin:0 auto;padding:35px;color:#333}.cv-combination header{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:3px solid #2196F3;padding-bottom:15px;margin-bottom:20px}.cv-combination header h1{font-size:26px;color:#1565C0;margin-bottom:3px}.cv-combination header .title{font-size:14px;color:#666}.cv-combination header .contact{font-size:12px;color:#777;text-align:right;line-height:1.8}.cv-combination h2{font-size:14px;color:#1565C0;text-transform:uppercase;letter-spacing:1px;margin:18px 0 10px;padding-bottom:5px;border-bottom:1px solid #e0e0e0}.cv-combination .summary{font-size:14px;line-height:1.7}.cv-combination .highlight-item{font-size:13px;padding:5px 0;padding-left:15px;position:relative}.cv-combination .highlight-item::before{content:"";position:absolute;left:0;top:12px;width:8px;height:8px;background:#2196F3;border-radius:50%}.cv-combination .experience-entry{margin-bottom:15px}.cv-combination .entry-header{display:flex;justify-content:space-between}.cv-combination .entry-title{font-weight:bold;font-size:14px}.cv-combination .entry-company{font-size:13px;color:#1565C0}.cv-combination .entry-date{font-size:12px;color:#999}.cv-combination .entry-description{font-size:13px;line-height:1.6;margin-top:4px}.cv-combination .skill-item{display:inline-block;background:#e3f2fd;color:#1565C0;padding:3px 10px;margin:3px;font-size:12px;border-radius:3px}',
10),

('Chronological', 'chronological', 'Timeline-focused layout emphasizing career progression and dates.', 'professional',
'<div class="cv-chronological"><header><h1>{{first_name}} {{last_name}}</h1><div class="contact">{{contact_entries}}</div></header><section class="summary"><h2>Objective</h2><p>{{summary}}</p></section><section class="experience"><h2>Work History</h2>{{experience_entries}}</section><section class="education"><h2>Education</h2>{{education_entries}}</section><section class="skills"><h2>Skills & Abilities</h2>{{skills_entries}}</section></div>',
'.cv-chronological{font-family:Arial,sans-serif;max-width:800px;margin:0 auto;padding:35px;color:#222}.cv-chronological header{text-align:center;border-bottom:2px solid #222;padding-bottom:15px;margin-bottom:20px}.cv-chronological header h1{font-size:24px;text-transform:uppercase;letter-spacing:3px;margin-bottom:5px}.cv-chronological header .contact{font-size:13px;color:#555}.cv-chronological h2{font-size:14px;text-transform:uppercase;background:#222;color:#fff;padding:6px 12px;margin:18px 0 12px}.cv-chronological .summary{font-size:14px;line-height:1.7;margin-bottom:15px}.cv-chronological .experience-entry{margin-bottom:18px;display:grid;grid-template-columns:140px 1fr;gap:15px}.cv-chronological .entry-date{font-size:12px;color:#666;text-align:right;padding-top:2px}.cv-chronological .entry-title{font-weight:bold;font-size:15px}.cv-chronological .entry-company{font-size:13px;color:#444}.cv-chronological .entry-description{font-size:13px;line-height:1.6;margin-top:5px}.cv-chronological .education-entry{margin-bottom:12px}.cv-chronological .skill-item{font-size:13px;display:inline-block;margin-right:15px}',
11),

('Elegant', 'elegant', 'Refined typography with subtle gold accents for law and consulting.', 'executive',
'<div class="cv-elegant"><header><h1>{{first_name}} {{last_name}}</h1><p class="title">{{job_title}}</p><div class="divider"></div><div class="contact">{{contact_entries}}</div></header><section class="summary"><h2>Profile</h2><p>{{summary}}</p></section><section class="experience"><h2>Experience</h2>{{experience_entries}}</section><section class="education"><h2>Education</h2>{{education_entries}}</section><section class="skills"><h2>Expertise</h2>{{skills_entries}}</section></div>',
'.cv-elegant{font-family:"Cormorant Garamond",Georgia,serif;max-width:780px;margin:0 auto;padding:45px 40px;color:#2c2c2c}.cv-elegant header{text-align:center;margin-bottom:30px}.cv-elegant header h1{font-size:34px;font-weight:400;letter-spacing:4px;margin-bottom:5px}.cv-elegant header .title{font-size:14px;letter-spacing:3px;color:#b8860b;text-transform:uppercase;margin-bottom:15px}.cv-elegant header .divider{width:60px;height:2px;background:#b8860b;margin:0 auto 15px}.cv-elegant header .contact{font-size:12px;color:#777;letter-spacing:1px}.cv-elegant h2{font-size:13px;text-transform:uppercase;letter-spacing:4px;color:#b8860b;text-align:center;margin:25px 0 15px;position:relative}.cv-elegant h2::after{content:"";display:block;width:40px;height:1px;background:#b8860b;margin:8px auto 0}.cv-elegant .summary{font-size:15px;line-height:1.9;text-align:center;color:#444;font-style:italic}.cv-elegant .experience-entry{margin-bottom:20px;text-align:center}.cv-elegant .entry-title{font-size:17px;font-weight:600}.cv-elegant .entry-company{font-size:14px;color:#b8860b}.cv-elegant .entry-date{font-size:12px;color:#999;letter-spacing:1px}.cv-elegant .entry-description{font-size:14px;line-height:1.7;color:#444;margin-top:5px;max-width:600px;margin-left:auto;margin-right:auto}.cv-elegant .skill-item{font-size:13px;color:#555;display:inline-block;margin:4px 12px;letter-spacing:1px}',
12),

('Bold', 'bold', 'Strong visual hierarchy with large headers and impactful design.', 'creative',
'<div class="cv-bold"><div class="header-block"><h1>{{first_name}} {{last_name}}</h1><p class="title">{{job_title}}</p><div class="contact">{{contact_entries}}</div></div><section class="summary"><h2>About</h2><p>{{summary}}</p></section><section class="experience"><h2>Experience</h2>{{experience_entries}}</section><section class="education"><h2>Education</h2>{{education_entries}}</section><section class="skills"><h2>Skills</h2>{{skills_entries}}</section></div>',
'.cv-bold{font-family:"Impact","Arial Black",sans-serif;max-width:800px;margin:0 auto}.cv-bold .header-block{background:#e74c3c;color:#fff;padding:40px;text-align:center}.cv-bold .header-block h1{font-size:42px;letter-spacing:2px;margin-bottom:5px}.cv-bold .header-block .title{font-size:18px;font-family:"Arial",sans-serif;opacity:0.9;margin-bottom:10px}.cv-bold .header-block .contact{font-size:13px;font-family:"Arial",sans-serif;opacity:0.8}.cv-bold h2{font-size:22px;background:#2c3e50;color:#fff;padding:10px 20px;margin:0;letter-spacing:1px}.cv-bold .summary{padding:25px;font-family:"Arial",sans-serif;font-size:15px;line-height:1.7;color:#444}.cv-bold .experience-entry{padding:20px 25px;border-bottom:1px solid #eee;font-family:"Arial",sans-serif}.cv-bold .entry-title{font-size:18px;font-weight:700;color:#2c3e50}.cv-bold .entry-company{font-size:14px;color:#e74c3c}.cv-bold .entry-date{font-size:12px;color:#999}.cv-bold .entry-description{font-size:14px;line-height:1.6;color:#444;margin-top:5px}.cv-bold .education-entry{padding:15px 25px;font-family:"Arial",sans-serif}.cv-bold .skill-item{display:inline-block;background:#2c3e50;color:#fff;padding:6px 14px;margin:4px;font-family:"Arial",sans-serif;font-size:12px}',
13),

('Professional', 'professional', 'Balanced, ATS-friendly layout suitable for all industries.', 'professional',
'<div classcv-professional"><header><h1>{{first_name}} {{last_name}}</h1><div class="contact">{{contact_entries}}</div></header><section class="summary"><h2>Professional Summary</h2><p>{{summary}}</p></section><section class="experience"><h2>Experience</h2>{{experience_entries}}</section><section class="education"><h2>Education</h2>{{education_entries}}</section><section class="skills"><h2>Skills</h2>{{skills_entries}}</section><section class="certifications"><h2>Certifications</h2>{{certification_entries}}</section></div>',
'.cv-professional{font-family:Calibri,"Trebuchet MS",sans-serif;max-width:800px;margin:0 auto;padding:35px;color:#333}.cv-professional header{margin-bottom:20px}.cv-professional header h1{font-size:24px;color:#2c3e50;margin-bottom:5px}.cv-professional header .contact{font-size:13px;color:#666}.cv-professional h2{font-size:15px;color:#2c3e50;border-bottom:2px solid #2c3e50;padding-bottom:4px;margin:18px 0 10px}.cv-professional .summary{font-size:14px;line-height:1.7;margin-bottom:15px}.cv-professional .experience-entry{margin-bottom:15px}.cv-professional .entry-header{display:flex;justify-content:space-between;align-items:baseline}.cv-professional .entry-title{font-weight:bold;font-size:14px}.cv-professional .entry-company{font-size:13px;color:#2c3e50}.cv-professional .entry-date{font-size:12px;color:#888}.cv-professional .entry-description{font-size:13px;line-height:1.6;margin-top:4px}.cv-professional .education-entry{margin-bottom:10px}.cv-professional .skill-item{font-size:13px;display:inline-block;margin-right:12px;margin-bottom:4px}.cv-professional .certification-entry{font-size:13px;margin-bottom:5px}',
14),

('Fresh', 'fresh', 'Modern, vibrant design for young professionals and recent graduates.', 'minimal',
'<div class="cv-fresh"><div class="header-fresh"><div class="name-side"><h1>{{first_name}} {{last_name}}</h1><p class="title">{{job_title}}</p></div><div class="contact-side">{{contact_entries}}</div></div><section class="summary"><h2>Summary</h2><p>{{summary}}</p></section><section class="experience"><h2>Experience</h2>{{experience_entries}}</section><section class="education"><h2>Education</h2>{{education_entries}}</section><section class="skills"><h2>Skills</h2>{{skills_entries}}</section><section class="interests"><h2>Interests</h2>{{interest_entries}}</section></div>',
'.cv-fresh{font-family:"Nunito",sans-serif;max-width:800px;margin:0 auto;padding:0;overflow:hidden}.cv-fresh .header-fresh{background:linear-gradient(135deg,#43e97b 0%,#38f9d7 100%);padding:30px 35px;display:flex;justify-content:space-between;align-items:center}.cv-fresh .header-fresh h1{font-size:28px;font-weight:800;color:#fff;margin-bottom:3px}.cv-fresh .header-fresh .title{font-size:14px;color:rgba(255,255,255,0.85);font-weight:500}.cv-fresh .header-fresh .contact-side{font-size:12px;color:rgba(255,255,255,0.9);text-align:right;line-height:1.9}.cv-fresh h2{font-size:14px;font-weight:700;color:#43e97b;margin:20px 0 10px;padding-left:12px;border-left:4px solid #43e97b}.cv-fresh .summary{padding:0 35px;font-size:14px;line-height:1.7;color:#555}.cv-fresh .experience-entry{padding:12px 35px;margin-bottom:10px}.cv-fresh .entry-title{font-weight:700;font-size:15px;color:#333}.cv-fresh .entry-company{font-size:13px;color:#43e97b}.cv-fresh .entry-date{font-size:11px;color:#aaa}.cv-fresh .entry-description{font-size:13px;line-height:1.6;color:#555;margin-top:4px}.cv-fresh .education-entry{padding:8px 35px}.cv-fresh .skill-item{background:linear-gradient(135deg,#43e97b,#38f9d7);color:#fff;padding:4px 12px;margin:3px;border-radius:15px;font-size:12px;display:inline-block}.cv-fresh .interest-item{display:inline-block;font-size:13px;color:#666;margin:3px 10px}',
15);
